def gen(rng, size):
    g = rng.randint(1, 5)
    groups = max(1, size // g)
    hand = []
    for _ in range(groups):
        start = rng.randint(0, 1000)
        for d in range(g):
            hand.append(start + d)
    rng.shuffle(hand)
    return [hand, g]

