class Solution:
    def isNStraightHand(self, hand, groupSize):
        if len(hand) % groupSize != 0:
            return False
        from collections import Counter
        cnt = Counter(hand)
        for v in sorted(cnt):
            c = cnt[v]
            if c <= 0:
                continue
            for d in range(groupSize):
                if cnt[v + d] < c:
                    return False
                cnt[v + d] -= c
        return True

