import heapq
class Solution:
    def isNStraightHand(self, hand, groupSize):
        if len(hand) % groupSize != 0:
            return False
        from collections import Counter
        cnt = Counter(hand)
        heap = list(cnt.keys())
        heapq.heapify(heap)
        while heap:
            start = heap[0]
            need = cnt[start]
            for v in range(start, start + groupSize):
                if cnt[v] < need:
                    return False
                cnt[v] -= need
                if cnt[v] == 0:
                    if v != heap[0]:
                        return False
                    heapq.heappop(heap)
        return True

