var isNStraightHand = function(hand, groupSize) {
    if (hand.length % groupSize !== 0) return false;
    const cnt = new Map();
    for (const v of hand) cnt.set(v, (cnt.get(v) || 0) + 1);
    const keys = [...cnt.keys()].sort((a, b) => a - b);
    for (const start of keys) {
        const need = cnt.get(start);
        if (need <= 0) continue;
        for (let v = start; v < start + groupSize; v++) {
            const c = cnt.get(v) || 0;
            if (c < need) return false;
            cnt.set(v, c - need);
        }
    }
    return true;
};
